// Generated by build_form_workflow.py — form submission -> Plane work item payload.
// Plane create body: name (required), description_html, priority,
// assignees[] (member UUIDs), target_date/start_date (YYYY-MM-DD).
const f = $json;

const FIELDS         = [{"label": "NAMA NASABAH", "isLink": false}, {"label": "NOMINAL PENGAJUAN PEMBIAYAAN", "isLink": false}, {"label": "PENILAIAN APPRAISAL", "isLink": false}, {"label": "DOKUMEN PENGAJUAN", "isLink": true}, {"label": "OBJEK PENILAIAN", "isLink": false}, {"label": "KETERANGAN TAMBAHAN (JIKA ADA)", "isLink": false}, {"label": "ATASAN USER", "isLink": false}];          // [{label, isLink}]
const ASSIGNEE_FIELD = "ATASAN USER";  // "" or the user-picker field label
const MEMBER_MAP     = {"Danny Dwi Cahyono (dcahyono@hijra.id)": "f799f9fe-ed67-427c-8e51-199de6cd54a6"};      // friendly label -> Plane member UUID
const TITLE_TEMPLATE = "{PENILAIAN APPRAISAL} – {NAMA NASABAH}";  // uses {FIELD LABEL} tokens
const PRIORITY       = "none";        // urgent|high|medium|low|none
const DATE_MAPPINGS  = {};   // {field label: "target_date"|"start_date"}

const get = (l) => (f[l] == null ? '' : String(f[l])).trim();
const esc = (s) => String(s == null ? '' : s)
  .replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
const linkify = (u) => {
  const s = String(u || '').trim();
  if (!s) return '<em>(kosong)</em>';
  return /^https?:\/\//i.test(s) ? ('<a href="' + esc(s) + '">' + esc(s) + '</a>') : esc(s);
};

// --- Title ---
let name = TITLE_TEMPLATE.replace(/\{([^}]+)\}/g, (_, k) => get(k)).replace(/\s+/g, ' ').trim();
if (!name) name = (get((FIELDS[0] || {}).label) || 'Untitled');

// --- Assignee (hit -> set; miss -> capture in description) ---
let assignees = [];
let unresolvedAssignee = '';
if (ASSIGNEE_FIELD) {
  const lbl = get(ASSIGNEE_FIELD);
  if (MEMBER_MAP[lbl]) assignees = [MEMBER_MAP[lbl]];
  else if (lbl) unresolvedAssignee = lbl;
}

// --- Description (HTML) — audit trail of every field ---
const rows = [];
for (const fld of FIELDS) {
  if (fld.label === ASSIGNEE_FIELD) continue;     // shown via assignee handling
  if (DATE_MAPPINGS[fld.label]) continue;          // promoted to a Plane date field
  const v = get(fld.label);
  rows.push('<p><strong>' + esc(fld.label) + ':</strong> '
    + (fld.isLink ? ('<br/>' + linkify(v)) : esc(v)) + '</p>');
}
if (unresolvedAssignee) {
  rows.push('<p><strong>' + esc(ASSIGNEE_FIELD)
    + ' (belum terpetakan ke member Plane):</strong> ' + esc(unresolvedAssignee) + '</p>');
}
rows.push('<hr/>');
rows.push('<p><em>Dibuat via n8n form.</em></p>');
const description_html = rows.join('\n');

// --- Plane create body ---
const body = {
  name: name,
  description_html: description_html,
  priority: PRIORITY,
  assignees: assignees,
};
for (const lbl of Object.keys(DATE_MAPPINGS)) {
  const v = get(lbl);
  if (v) body[DATE_MAPPINGS[lbl]] = v;   // n8n date field yields YYYY-MM-DD
}

return { body: body };
